parameters.jsCode:
return items.map(item => {
  const htmlContent = item.json["data"]; // ou ajuste se o nome da propriedade for diferente

  const extractPlainText = (html) => {
    if (!html) return "";

    const withoutScriptsAndStyles = html
      .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "")
      .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "");

    const strippedText = withoutScriptsAndStyles.replace(/<\/?[^>]+(>|$)/g, "");

    const decodedText = strippedText
      .replace(/&nbsp;/gi, " ")
      .replace(/&amp;/gi, "&")
      .replace(/&lt;/gi, "<")
      .replace(/&gt;/gi, ">")
      .replace(/&quot;/gi, "\"")
      .replace(/&#39;/gi, "'");

    const cleanedText = decodedText.replace(/\s+/g, " ").trim();

    return cleanedText;
  };

  const textoFinal = extractPlainText(htmlContent);

  return {
    json: {
      textoFinal,
    },
  };
});
